import { type PropsWithChildren } from 'react';

import { CategoricalBarFilteredDataContext } from '../contexts/CategoricalBarFilteredData.context.js';
import { useFilteredDimensionsState } from '../hooks/store/selectors.js';
import { useCategoricalBarChartData } from '../hooks/useCategoricalBarChartData.js';
import { useGenerateFilteredCategoricalBarData } from '../hooks/useGenerateFilteredCategoricalBarData.js';
import type { CategoricalBarData } from '../types/categorical-bar-chart-data.js';

export const CategoricalBarFilteredDataProvider = ({
  children,
}: PropsWithChildren) => {
  const {
    categoricalData,
    unit,
    categoryMap: initialCategoryMap,
    dimensionMap: initialDimensionMap,
    valueRepresentation,
  } = useCategoricalBarChartData();
  const filteredDimensions = useFilteredDimensionsState();

  const filteredCategories: CategoricalBarData[] =
    filteredDimensions.size > 0
      ? categoricalData.map((category) => ({
          ...category,
          dimensions: category.dimensions.filter(({ name }) =>
            filteredDimensions.has(name),
          ),
        }))
      : categoricalData;

  const {
    categoryMap,
    dimensionMap,
    filteredUniqueDimensions,
    minMaxPerUnit,
    isSingleDimension,
  } = useGenerateFilteredCategoricalBarData(
    filteredCategories,
    categoricalData,
    unit,
    initialCategoryMap,
    initialDimensionMap,
    valueRepresentation,
  );

  return (
    <CategoricalBarFilteredDataContext.Provider
      value={{
        filteredCategories,
        filteredDimensions: filteredUniqueDimensions,
        minMaxPerUnit,
        isSingleDimension,
        categoryMap,
        dimensionMap,
        unit,
      }}
    >
      {children}
    </CategoricalBarFilteredDataContext.Provider>
  );
};
